                        return count++;
                    }
                });
                data.latest_count_bell = count;
                if (cookieData != '') {
                    setNewsCount(data);             
                } else {
                    if (data.unix_datatime) {
                        setNotiCookie(_aajtakBKCookie, _aajtakBKCookieExp, data.unix_datatime);
                        setNewsCount(data);
                        /*changeFavicon(favIconAlert);*/
                    }
                }
            }
        });
    }

